/* wms-master-stationmgmt-sql-oracle.xml - selectStationMgmtList */
SELECT '0' AS CHK , STN.CTKEY , CT.CTNM , STN.STNDIVCD , STN.CLASSIFDIVCD , STN.CLASSIFTYPECD , STN.CELLALCRITCD , STN.STNNO , STN.STNFACNO , STN.STNBARCODE , STN.WIDTH , STN.DEPTH , STN.HEIGHT , STN.CBMSTARTRNG , STN.CBMCLOSRNG , STN.USEYN , STN.INSERTDATE , STN.INSERTURKEY , STN.UPDATEDATE , STN.UPDATEURKEY
ORDER BY STN.UPDATEDATE DESC

/* wms-master-stationmgmt-sql-oracle.xml - selectCheckDupStationMgmt */
SELECT COUNT(*)
  FROM TWORK_MST_STN
 WHERE STNFACNO = #{stnfacno}

mapper.insert:
/* wms-master-stationmgmt-sql-oracle.xml - insertStationMgmt */

	SELECT #{stnfacno} || TO_CHAR(CURRENT_TIMESTAMP,'YYYY')


INSERT INTO TWORK_MST_STN (
       CTKEY
	 , STNDIVCD
	 , CLASSIFDIVCD
	 , CLASSIFTYPECD
	 , CELLALCRITCD
	 , STNNO
	 , STNFACNO
	 , STNBARCODE
	 , WIDTH
	 , DEPTH
	 , HEIGHT
	 , CBMSTARTRNG
	 , CBMCLOSRNG
	 , USEYN
	 , INSERTDATE
	 , INSERTURKEY
	 , UPDATEDATE
	 , UPDATEURKEY
	 )
VALUES (
	   #{ctkey}
	 , #{stndivcd}
	 , #{classifdivcd}
	 , #{classiftypecd}
  	 , #{cellalcritcd}
	 , #{stnno}
	 , #{stnfacno}
	 , #{stnbarcode}
     , COALESCE(#{width}, 0)
     , COALESCE(#{depth}, 0)
     , COALESCE(#{height}, 0)
     , COALESCE(#{cbmstartrng}, 0)
     , COALESCE(#{cbmclosrng}, 0)
     , #{useyn}
     , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
     , #{surkey}
     , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
     , #{surkey}
	 )

/* wms-master-stationmgmt-sql-oracle.xml - insertStationWkCell */ INSERT INTO TWORK_MST_STNWKCELL ( CTKEY , STNBARCODE , CELLBARCODE , DIRTDIVCD , ROWNO , COLNO , CELLNO , RTYN , USEYN , INSERTDATE , INSERTURKEY , UPDATEDATE , UPDATEURKEY ) SELECT CTKEY , #{stnbarcode} AS STNBARCODE , CASE WHEN STNDIVCD = '10' THEN 'D'||'-'||#{stnno}||'-'||DIRTDIVCD||'-'||CELLNO WHEN STNDIVCD = '20' THEN 'MD'||#{stnno}||CELLNO END AS CELLBARCODE , DIRTDIVCD , ROWNO , COLNO , CELLNO , RTYN , CASE WHEN STNDIVCD = '20' AND COALESCE(#{classifdivcd}, ' ') = '10' AND CELLNO IN ('01','11','21') THEN 'N' ELSE 'Y' END AS USEYN , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS') , #{surkey} , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS') , #{surkey} FROM TWORK_MST_STN_CELL_SET WHERE CTKEY = #{ctkey} AND STNDIVCD = #{stndivcd}
AND CLASSIFDIVCD = #{classifdivcd}
AND CLASSIFTYPECD = #{classiftypecd}

mapper.delete:
/* wms-master-stationmgmt-sql-oracle.xml - deleteStationMgmt */
DELETE
  FROM TWORK_MST_STN
 WHERE CTKEY = #{ctkey}
   AND STNBARCODE = #{stnbarcode}

/* wms-master-stationmgmt-sql-oracle.xml - deleteStationWkCell */
DELETE
FROM TWORK_MST_STNWKCELL
WHERE CTKEY = #{ctkey}
  AND STNBARCODE = #{stnbarcode}

mapper.update:
/* wms-master-stationmgmt-sql-oracle.xml - updateStationMgmt */
UPDATE TWORK_MST_STN
   SET WIDTH = COALESCE(#{width}, 0)
	 , DEPTH = COALESCE(#{depth}, 0)
	 , HEIGHT = COALESCE(#{height}, 0)
	 , CBMSTARTRNG = COALESCE(#{cbmstartrng}, 0)
	 , CBMCLOSRNG = COALESCE(#{cbmclosrng}, 0)
	 , USEYN = #{useyn}
	 , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND STNBARCODE = #{stnbarcode}

mapper.select:
/* wms-master-stationmgmt-sql-oracle.xml - selectWkCellUseYn */
SELECT 'CELL'||CELLNO AS CELLNO
     , USEYN
  FROM TWORK_MST_STNWKCELL
 WHERE CTKEY = #{ctkey}
   AND STNBARCODE = #{stnbarcode}
ORDER BY
      CELLNO

mapper.update:
/* wms-master-stationmgmt-sql-oracle.xml - updateStationCellalcritcd */
UPDATE TWORK_MST_STN
   SET CELLALCRITCD = #{cellalcritcd}
	 , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	 , UPDATEURKEY = #{surkey}

   AND CTKEY = #{ctkey}



			AND CLASSIFDIVCD = #{classifdivcd}
			AND CLASSIFTYPECD = #{classiftypecd}


			AND STNBARCODE = #{stnbarcode}


			AND 1 = 2

		/* wms-master-stationmgmt-sql-oracle.xml - updateStationCell */
		UPDATE TWORK_MST_STNWKCELL
		   SET UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
			 , UPDATEURKEY = #{surkey}
             , PRINO = #{prino}

			AND CTKEY = #{ctkey}
            AND CELLNO = #{cellno}


					AND STNBARCODE IN (
						SELECT STNBARCODE
						  FROM TWORK_MST_STN
						 WHERE CTKEY = #{ctkey}
						   AND CLASSIFDIVCD = #{classifdivcd}
						   AND CLASSIFTYPECD = #{classiftypecd}
					  )


					AND STNBARCODE = #{stnbarcode}


					AND 1 = 2

/* wms-master-stationmgmt-sql-oracle.xml - updateStationWkCellUseYn */
UPDATE TWORK_MST_STNWKCELL
   SET USEYN = #{useyn}
	 , PRINO = null
	 , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND STNBARCODE = #{stnbarcode}
   AND DIRTDIVCD = #{dirtdivcd}
   AND CELLNO = #{cellno}

/* wms-master-stationmgmt-sql-oracle.xml - updateStationWkCell */
UPDATE TWORK_MST_STNWKCELL
   SET PRINO = #{prino}
     , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
     , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}



		AND STNBARCODE IN (
			SELECT STNBARCODE FROM TWORK_MST_STN WHERE CTKEY = #{ctkey} AND STNDIVCD = '10'
		)


		AND STNBARCODE = #{stnbarcode}



   AND DIRTDIVCD = #{dirtdivcd}
   AND CELLNO = #{cellno}

/* wms-master-stationmgmt-sql-oracle.xml - updateStationWkCellGroup */
UPDATE TWORK_MST_STNWKCELL
   SET GRPNO = #{grpno}
     , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
     , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}



		AND STNBARCODE IN (
			SELECT STNBARCODE FROM TWORK_MST_STN WHERE CTKEY = #{ctkey} AND STNDIVCD = '10'
		)


		AND STNBARCODE = #{stnbarcode}



   AND ROWNO = #{rowno}

